// heatmap-2D.js - 2D热力图
// ✅ Inline CSV data (for heatmap)
(() => {
  // 等待DOM加载完成
  const init2DHeatmap = () => {
    // 使用 heatmap-2d 容器
    const container = document.getElementById("heatmap-2d") || document.getElementById("heatmap");
    if (!container) {
      console.error('❌ 找不到heatmap容器');
      return;
    }
    
    // 使用容器的ID进行选择
    const containerId = container.id;
    d3.select(`#${containerId}`).selectAll("*").remove();
    // ⚠️ 不要全局 remove：3D/2D 共享 tooltip，否则会互相删掉导致“tooltip 没了”

    const csvData = `month,classical,electronic,folk,jazz,pop,rock,ACG,rap
2023-12,35,34,64,47,24,32,37,37
2024-01,35,33,58,46,23,31,32,36
2024-02,34,32,62,48,26,33,34,39
2024-03,35,34,59,48,23,34,37,38
2024-04,31,34,55,47,21,34,31,36
2024-05,32,48,57,46,24,34,32,38
2024-06,32,49,62,48,23,36,31,40
2024-07,31,38,64,49,25,32,31,38
2024-08,30,39,62,46,23,32,32,37
2024-09,32,35,60,45,23,36,33,45
2024-10,31,32,60,49,23,33,31,46
2024-11,35,33,58,45,22,32,32,39
2024-12,35,35,63,48,23,33,37,39
2025-01,32,34,54,47,22,32,32,38
2025-02,33,33,58,48,22,31,29,42
2025-03,33,32,56,48,22,31,31,36
2025-04,31,33,59,45,22,31,30,36
2025-05,30,37,58,46,23,32,30,39
2025-06,29,33,57,46,21,32,31,36
2025-07,29,36,60,48,21,39,31,38
2025-08,31,35,59,46,22,34,31,34
2025-09,30,32,61,46,22,33,30,32
2025-10,33,33,59,44,21,34,31,36
2025-11,31,32,57,46,21,33,30,33
2025-12,33,32,60,45,23,32,33,39
`;

  const data = d3.csvParse(csvData.trim());

  // ✅ Genre keys（与你原逻辑一致）
  const genres = ["ACG", "classical", "electronic", "folk", "jazz", "pop", "rap", "rock"];
  const months = data.map(d => d["month"]);

  const heatmapData = data.flatMap(row =>
    genres.map(genre => ({
      month: row["month"],
      genre,
      value: +row[genre]
    }))
  );

  // === 自适应尺寸计算 ===
  // 使用与上面相同的容器
  const heatmapContainer = container;
  const containerWidth = heatmapContainer.clientWidth || 900;
  const containerHeight = heatmapContainer.clientHeight || 320;

  const margin = {
    top: Math.max(22, containerHeight * 0.10),
    right: Math.max(18, containerWidth * 0.03),
    bottom: Math.max(46, containerHeight * 0.18),
    left: Math.max(64, containerWidth * 0.10)
  };

  const width = containerWidth - margin.left - margin.right;
  const height = containerHeight - margin.top - margin.bottom;

  const root = d3.select(`#${containerId}`)
    .append("svg")
    .attr("width", "100%")
    .attr("height", "100%")
    .attr("viewBox", `0 0 ${containerWidth} ${containerHeight}`)
    .attr("preserveAspectRatio", "xMidYMid meet");

  // ✅ 背景“卡片内衬”（深色赛博主题下保持克制，不抢色块）
  root.append("rect")
    .attr("x", 10)
    .attr("y", 10)
    .attr("width", containerWidth - 20)
    .attr("height", containerHeight - 20)
    .attr("rx", 14)
    .attr("ry", 14)
    .attr("fill", "rgba(7, 3, 18, 0.18)")
    .attr("stroke", "rgba(50, 167, 255, 0.16)");

  const svg = root.append("g")
    .attr("transform", `translate(${margin.left},${margin.top})`);

  // === Axes ===
  const x = d3.scaleBand().range([0, width]).domain(months).padding(0.08);
  const y = d3.scaleBand().range([height, 0]).domain(genres).padding(0.10);

  const css = getComputedStyle(document.documentElement);
  const axisColor = (css.getPropertyValue("--axis-text-strong") || "").trim() || "rgba(226, 232, 240, 0.88)";
  const gridColor = (css.getPropertyValue("--axis-grid") || "").trim() || "rgba(50, 167, 255, 0.12)";

  const cssVar = (name, fallback) => (css.getPropertyValue(name) || "").trim() || fallback;
  const accentBlue = cssVar("--accent-blue", "#32a7ff");
  const accentViolet = cssVar("--accent-violet", "#7c3aed");
  const accentPink = cssVar("--accent-pink", "#ff3bd4");
  const accentCyan = cssVar("--accent-cyan", "#00fff0");

  const xAxis = svg.append("g")
    .attr("transform", `translate(0, ${height})`)
    .call(d3.axisBottom(x).tickSizeOuter(0));

  if (months.length > 12 || containerWidth < 560) {
    xAxis.selectAll("text")
      .attr("transform", "rotate(-45)")
      .style("text-anchor", "end")
      .attr("dx", "-0.45em")
      .attr("dy", "0.55em");
  }

  xAxis.selectAll("path, line").attr("stroke", "rgba(50, 167, 255, 0.26)");
  xAxis.selectAll("text")
    .attr("fill", axisColor)
    .style("font-size", "12px")
    .style("paint-order", "stroke")
    .style("stroke", "rgba(7, 3, 18, 0.72)")
    .style("stroke-width", "2.0px")
    .style("stroke-linejoin", "round");

  const yAxis = svg.append("g")
    .call(d3.axisLeft(y).tickSizeOuter(0));

  yAxis.selectAll("path, line").attr("stroke", "rgba(50, 167, 255, 0.26)");
  yAxis.selectAll("text")
    .attr("fill", axisColor)
    .style("font-size", "12px")
    .style("paint-order", "stroke")
    .style("stroke", "rgba(7, 3, 18, 0.72)")
    .style("stroke-width", "2.0px")
    .style("stroke-linejoin", "round");

  // === ✅ 颜色：赛博霓虹渐变（与页面主题色一致） ===
  const vMin = d3.min(heatmapData, d => d.value);
  const vMax = d3.max(heatmapData, d => d.value);

  // 赛博渐变：进一步提亮下界，并降低粉色段强度（避免 pop 行过于突出）
  // 渐变段数收敛到 4 段：彻底去掉“黑段”，低值直接从亮蓝底开始
  // 目标：整体更亮、更赛博；粉色只在高值端出现
  const cyberStops = [
    "#2a4e8f",   // 亮蓝底（低值不黑）
    accentViolet, // 紫
    accentCyan,  // 青
    "#ff5adf"    // 柔粉（最高值端）
  ];
  const cyberInterpolator = d3.interpolateRgbBasis(cyberStops);

  const colorScale = d3.scaleSequential()
    .domain([vMin, vMax])
    .interpolator(cyberInterpolator);

  // === 颜色映射图例（2D/3D 共用容器）===
  (function updateLegend() {
    const legend = document.getElementById("heatmap-color-legend");
    if (!legend) return;
    const fmt = d3.format(",d");
    legend.innerHTML = `
      <div class="legend-title">Score → Color</div>
      <div class="legend-bar" style="background: linear-gradient(90deg, ${cyberStops.join(",")});"></div>
      <div class="legend-labels">
        <span>${fmt(vMin ?? 0)}</span>
        <span>${fmt(vMax ?? 0)}</span>
      </div>
    `;
  })();

  // === Tooltip（2D/3D 复用同一个）===
  let tooltip = d3.select("body").select(".heatmap-tooltip");
  if (tooltip.empty()) {
    tooltip = d3.select("body").append("div").attr("class", "heatmap-tooltip");
  }
  tooltip
    // 与全局 tooltip 样式一致：fixed + clientX/clientY，避免缩放/滚动错位
    .style("position", "fixed")
    .style("pointer-events", "none")
    .style("opacity", 0)
    .style("padding", "10px 12px")
    .style("border-radius", "12px")
    .style("background", "rgba(30,41,59,0.92)")
    .style("color", "#fff")
    .style("font", '13px/1.35 system-ui,-apple-system,"Segoe UI","Microsoft YaHei",sans-serif')
    .style("box-shadow", "0 10px 24px rgba(0,0,0,0.16)")
    .style("z-index", 1000);

  // === Heatmap cells ===
  svg.selectAll("rect.cell")
    .data(heatmapData)
    .enter()
    .append("rect")
    .attr("class", "cell")
    .attr("x", d => x(d.month))
    .attr("y", d => y(d.genre))
    .attr("width", x.bandwidth())
    .attr("height", y.bandwidth())
    .attr("rx", 8)
    .attr("ry", 8)
    .attr("fill", d => colorScale(d.value))
    .attr("stroke", gridColor)
    .attr("stroke-width", 1)
    .on("mousemove", (event, d) => {
      tooltip.style("opacity", 1).html(`<b>${d.genre}</b><br/>${d.month}<br/>Value: ${d.value}`);
      const cx = (event && typeof event.clientX === "number") ? event.clientX : (event && typeof event.pageX === "number" ? event.pageX : 0);
      const cy = (event && typeof event.clientY === "number") ? event.clientY : (event && typeof event.pageY === "number" ? event.pageY : 0);
      const node = tooltip.node();
      const w = node ? (node.offsetWidth || 0) : 0;
      const h = node ? (node.offsetHeight || 0) : 0;
      const pad = 10;
      let x = cx + 12;
      let y = cy - 18;
      x = Math.max(pad, Math.min(x, (window.innerWidth || 0) - w - pad));
      y = Math.max(pad, Math.min(y, (window.innerHeight || 0) - h - pad));
      tooltip.style("left", `${x}px`).style("top", `${y}px`);
    })
    .on("mouseout", () => tooltip.style("opacity", 0));

  // === ✅ 折线更柔和：颜色统一、线更细、轻微光晕，点用“空心描边”避免白点突兀 ===
  // Glow filter
  const defs = root.append("defs");
  const glow = defs.append("filter").attr("id", "heatmapGlow");
  glow.append("feGaussianBlur").attr("stdDeviation", "1.8").attr("result", "coloredBlur");
  const feMerge = glow.append("feMerge");
  feMerge.append("feMergeNode").attr("in", "coloredBlur");
  feMerge.append("feMergeNode").attr("in", "SourceGraphic");

  const genreCenter = d => y(d.genre) + y.bandwidth() / 2;

  const line = d3.line()
    .x(d => x(d.month) + x.bandwidth() / 2)
    .y(d => genreCenter(d))
    .curve(d3.curveMonotoneX);

  // 数据保持你的原始逻辑（只是换颜色/样式）
  const lineData1 = [
    {"part": 1, "top_genre": "pop", "count": 6},
    {"part": 2, "top_genre": "pop", "count": 8},
    {"part": 3, "top_genre": "pop", "count": 7},
    {"part": 4, "top_genre": "pop", "count": 8},
    {"part": 5, "top_genre": "pop", "count": 8},
    {"part": 6, "top_genre": "pop", "count": 8},
    {"part": 7, "top_genre": "pop", "count": 8},
    {"part": 8, "top_genre": "pop", "count": 8},
    {"part": 9, "top_genre": "pop", "count": 8},
    {"part": 10, "top_genre": "pop", "count": 7},
    {"part": 11, "top_genre": "pop", "count": 6},
    {"part": 12, "top_genre": "pop", "count": 5},
    {"part": 13, "top_genre": "pop", "count": 7},
    {"part": 14, "top_genre": "pop", "count": 7},
    {"part": 15, "top_genre": "pop", "count": 6},
    {"part": 16, "top_genre": "pop", "count": 7},
    {"part": 17, "top_genre": "pop", "count": 5},
    {"part": 18, "top_genre": "pop", "count": 6},
    {"part": 19, "top_genre": "pop", "count": 8},
    {"part": 20, "top_genre": "pop", "count": 6},
    {"part": 21, "top_genre": "pop", "count": 6},
    {"part": 22, "top_genre": "pop", "count": 7},
    {"part": 23, "top_genre": "pop", "count": 5},
    {"part": 24, "top_genre": "pop", "count": 6},
    {"part": 25, "top_genre": "pop", "count": 6}
  ];

  const lineData2 = [
    {"part": 1, "top_genre": "rap", "count": 5},
    {"part": 2, "top_genre": "rap", "count": 6},
    {"part": 3, "top_genre": "rap", "count": 7},
    {"part": 4, "top_genre": "rap", "count": 6},
    {"part": 5, "top_genre": "rap", "count": 7},
    {"part": 6, "top_genre": "pop", "count": 6},
    {"part": 7, "top_genre": "pop", "count": 8},
    {"part": 8, "top_genre": "pop", "count": 7},
    {"part": 9, "top_genre": "pop", "count": 6},
    {"part": 10, "top_genre": "pop", "count": 6},
    {"part": 11, "top_genre": "pop", "count": 5},
    {"part": 12, "top_genre": "pop", "count": 5},
    {"part": 13, "top_genre": "pop", "count": 6},
    {"part": 14, "top_genre": "pop", "count": 7},
    {"part": 15, "top_genre": "pop", "count": 6},
    {"part": 16, "top_genre": "pop", "count": 7},
    {"part": 17, "top_genre": "pop", "count": 5},
    {"part": 18, "top_genre": "pop", "count": 6},
    {"part": 19, "top_genre": "pop", "count": 7},
    {"part": 20, "top_genre": "pop", "count": 7},
    {"part": 21, "top_genre": "pop", "count": 6},
    {"part": 22, "top_genre": "pop", "count": 7},
    {"part": 23, "top_genre": "pop", "count": 6},
    {"part": 24, "top_genre": "pop", "count": 5},
    {"part": 25, "top_genre": "pop", "count": 5}
  ];

  const linePoints1 = lineData1.map((d, i) => ({ month: months[i], genre: d.top_genre, count: +d.count }));
  const linePoints2 = lineData2.map((d, i) => ({ month: months[i], genre: d.top_genre, count: +d.count }));

  const theme = {
    ink: "rgba(36,52,71,0.70)",
    // 参考图二：蓝灰 + 豆沙（更统一）
    lineA: "#5B7AA6",
    lineB: "#C97A6E",
    dotFill: "#F7F4EC"
  };

  function drawTrend(points, color, cls) {
    svg.append("path")
      .datum(points)
      .attr("class", cls)
      .attr("fill", "none")
      .attr("stroke", color)
      .attr("stroke-width", 2.2)
      .attr("stroke-linejoin", "round")
      .attr("stroke-linecap", "round")
      .attr("opacity", 0.95)
      .attr("filter", "url(#heatmapGlow)")
      .attr("d", line);

    svg.selectAll(`circle.${cls}-pt`)
      .data(points)
      .enter()
      .append("circle")
      .attr("class", `${cls}-pt`)
      .attr("cx", d => x(d.month) + x.bandwidth() / 2)
      .attr("cy", d => genreCenter(d))
      .attr("r", d => 3.2 + d.count / 6)   // 更克制
      .attr("fill", theme.dotFill)         // 空心效果更干净
      .attr("stroke", color)
      .attr("stroke-width", 2)
      .attr("opacity", 0.95)
      .on("mousemove", (event, d) => {
        tooltip
          .style("opacity", 1)
          .html(`🎵 Genre: <b>${d.genre}</b><br/>${d.month}<br/>Count: ${d.count}`)
          .style("left", `${event.pageX + 12}px`)
          .style("top", `${event.pageY - 18}px`);
      })
      .on("mouseout", () => tooltip.style("opacity", 0));
  }

    drawTrend(linePoints1, theme.lineA, "trendA");
    drawTrend(linePoints2, theme.lineB, "trendB");

    console.log("✅ 2D Heatmap rendered (Morandi cool-warm + softer trends)");
  };
  
  // 导出初始化函数，允许外部调用
  window.init2DHeatmap = init2DHeatmap;
  
  // 等待容器有尺寸后再执行
  // 简化：如果容器被隐藏，使用默认尺寸继续
  const waitForContainer = () => {
    const container = document.getElementById("heatmap-2d") || document.getElementById("heatmap");
    if (!container) {
      console.error('❌ 找不到heatmap容器');
      return;
    }
    
    const width = container.offsetWidth || container.clientWidth;
    const height = container.offsetHeight || container.clientHeight;
    
    // 如果容器有尺寸，或者容器被隐藏（使用默认尺寸）
    if (width > 0 && height > 0) {
      init2DHeatmap();
    } else if (container.style.display === 'none') {
      // 如果容器被隐藏，使用默认尺寸继续
      console.log('⚠️ 容器被隐藏，使用默认尺寸继续');
      init2DHeatmap();
    } else {
      setTimeout(waitForContainer, 100);
    }
  };
  
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => {
      setTimeout(waitForContainer, 100);
    });
  } else {
    setTimeout(waitForContainer, 100);
  }
})();
